import java.io.*;
public class TransientField {
    static class Secret implements Serializable {
        String name;
        transient String password;
        Secret(String n, String p) { name=n; password=p; }
    }
    public static void main(String[] args) throws Exception {
        Secret s = new Secret("alice", "s3cr3t");
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        new ObjectOutputStream(baos).writeObject(s);
        Secret s2 = (Secret) new ObjectInputStream(
            new ByteArrayInputStream(baos.toByteArray())).readObject();
        System.out.println(s2.name);
        System.out.println(s2.password);
    }
}
